{"code": "import json
from collections import defaultdict

with open(locals()['var_functions.query_db:8'], 'r') as f:
    tracks = json.load(f)

with open(locals()['var_functions.query_db:9'], 'r') as f:
    sales = json.load(f)

# Build track info map
track_info = {}
for t in tracks:
    tid = t['track_id']
    title = t.get('title', '')
    artist = t.get('artist', '')

    # Extract artist from title if needed
    if ' - ' in title and (not artist or artist.lower() in ['none', 'unknown', '[unknown]']):
        parts = title.split(' - ', 1)
        artist = parts[0]
        title = parts[1]

    track_info[tid] = {
        'title': title.strip(),
        'artist': artist.strip() if artist and artist.lower() not in ['none', 'unknown', '[unknown]'] else 'Unknown',
        'album': t.get('album', '')
    }

# Find all tracks for the top song and verify revenue
target_songs = []
for tid, info in track_info.items():
    if 'groovey' in info['title'].lower() and 'matteson' in info['artist'].lower():
        target_songs.append(tid)

# Calculate exact revenue
exact_revenue = 0
for sale in sales:
    if sale['track_id'] in target_songs:
        exact_revenue += float(sale['revenue_usd'])

# Get representative track
target_data = []
for tid in target_songs[:3]:
    target_data.append(track_info[tid])

print("__RESULT__:")
print(json.dumps({
    'found_track_ids': len(target_songs),
    'revenue': exact_revenue,
    'sample_tracks': target_data
}, indent=2))"}

